#!/usr/bin/env python3
# Admin: delete a subscriber from the detail drawer. Adds a 'Danger zone' with a
# type-the-email confirmation that writes deletionRequests/{uid}, firing the
# existing processAccountDeletion Cloud Function (full teardown: Firestore data,
# stored videos, threads, the user doc, and the Auth sign-in). Hidden for the
# admin's own account. Also adds the Firestore rule allowing the admin (and a
# user for their own account) to create deletionRequests. Edits admin.html + firestore.rules.
import os, sys, base64
BASE = sys.argv[1] if len(sys.argv) > 1 else os.path.expanduser('~/weekly-briefing-local/test-repo')
EDITS = [
  ('admin.html', 'danger-html', 'ICAgICAgPGRpdiBpZD0iZC1ub3RlcyI+CiAgICAgICAgPHAgY2xhc3M9ImVtcHR5LXNlY3Rpb24iPk5vIG5vdGVzIHNhdmVkLjwvcD4KICAgICAgPC9kaXY+CiAgICA8L2Rpdj4=', ''),
  ('admin.html', 'opendetail-guard', 'ICBkb2N1bWVudC5nZXRFbGVtZW50QnlJZCgnZGV0YWlsJykuY2xhc3NMaXN0LmFkZCgnc2hvdycpOwp9Ow==', ''),
  ('admin.html', 'delete-fns', 'd2luZG93LmNsb3NlRGV0YWlsID0gZnVuY3Rpb24oKSB7CiAgZG9jdW1lbnQuZ2V0RWxlbWVudEJ5SWQoJ2RldGFpbCcpLmNsYXNzTGlzdC5yZW1vdmUoJ3Nob3cnKTsKICBjYW5jZWxFZGl0TmFtZSgpOwogIGN1cnJlbnREZXRhaWxVaWQgPSBudWxsOwp9Ow==', ''),
  ('firestore.rules', 'rules-deletionRequests', 'ICAgIC8vIEFkbWluLW9ubHkgc2VuZCBqb2IgcXVldWUKICAgIG1hdGNoIC9hZG1pblNlbmRzL3tqb2JJZH0gew==', ''),
]
from collections import defaultdict
byfile=defaultdict(list)
for rel,label,bo,bn in EDITS: byfile[rel].append((label,bo,bn))
for rel,items in byfile.items():
    path=os.path.join(BASE,rel)
    s=open(path,encoding='utf-8').read(); orig=len(s)
    for label,bo,bn in items:
        old=base64.b64decode(bo).decode('utf-8'); new=base64.b64decode(bn).decode('utf-8')
        c=s.count(old)
        if c!=1: raise SystemExit('Anchor [%s] in %s found %d times (expected 1). Aborting; nothing written.'%(label,rel,c))
        s=s.replace(old,new)
    tmp=path+'.tmp'; open(tmp,'w',encoding='utf-8').write(s); os.replace(tmp,path)
    print('OK %s: %d -> %d bytes (%+d).'%(rel,orig,len(s),len(s)-orig))
print('Done. Delete-subscriber control + Firestore rule applied.')
